import openai

class Chatbot:
    def __init__(self, api_key):
        self.api_key = api_key
        openai.api_key = self.api_key
        self.system_instructions = "You are a customer support assistant. Provide helpful and accurate information."

    def get_response(self, user_message):
        prompt = f"{self.system_instructions}\nUser: {user_message}\nAssistant:"
        response = openai.Completion.create(
            engine="text-davinci-003",
            prompt=prompt,
            max_tokens=150,
            n=1,
            stop=None,
            temperature=0.7
        )
        return response.choices[0].text.strip()

